SELECT department_id, COUNT(id) AS number_of_staff
FROM staff
GROUP BY department_id;

SELECT staff_id
FROM staff_leave
WHERE approval_status = 'approved';

SELECT SUM(expense_amount) AS total_expenses
FROM staff_expenses
WHERE staff_id = 0;

SELECT SUM(number_of_days) AS total_annual_leave_days
FROM staff_leave
WHERE leave_type = 'Annual Leave';

SELECT staff_id, AVG(performance_rating) AS average_rating
FROM staff_performance
GROUP BY staff_id;

SELECT name 
FROM staff 
ORDER BY joining_date ASC;

SELECT payment_reason
FROM staff_payment
WHERE payment_status = 'completed';

SELECT next_review_date
FROM staff_performance
WHERE staff_id = 1;
